#include<bits/stdc++.h>
using namespace std;
struct node{
    int w,ib;
}a[20005];
bool cmp(node x,node y){
	return (x.w!=y.w)?(x.w>y.w):(x.ib<y.ib);
}
int main(void){
	int n,k,e[10];
	cin>>n>>k;
	for(int i=0;i<10;i++)cin>>e[i];
	for(int i=1;i<=n;i++)cin>>a[i].w,a[i].ib=i;
	sort(a+1,a+1+n,cmp);
	for(int i=0;i<n;i++)a[i+1].w+=e[i%10];
    sort(a+1,a+1+n,cmp);
    for(int i=1;i<=k;i++)cout<<a[i].ib<<' ';
	return false;
}
